exercises.solution_code:
#include <iostream>
#include <string>
#include <string_view>

enum class Rarity
{
    Common    = 0,
    Rare      = 1,
    Legendary = 2
};

struct Item
{
    std::string name;
    int         quantity;
    Rarity      rarity;
};

std::string_view rarityLabel(Rarity r)
{
    switch (r)
    {
        case Rarity::Common:    return "Common";
        case Rarity::Rare:      return "Rare";
        case Rarity::Legendary: return "Legendary";
        default:                return "Unknown";
    }
}

int main()
{
    int n{};
    std::cin >> n;

    Item items[5];

    for (int i{ 0 }; i < n; ++i)
    {
        std::string name;
        int quantity{};
        int code{};
        std::cin >> name >> quantity >> code;
        items[i] = Item{ name, quantity, static_cast<Rarity>(code) };
    }

    int total{ 0 };
    for (int i{ 0 }; i < n; ++i)
    {
        std::cout << items[i].name << " x" << items[i].quantity
                  << " [" << rarityLabel(items[i].rarity) << "]\n";
        total += items[i].quantity;
    }

    std::cout << '\n';
    std::cout << "Total items: " << total << '\n';

    return 0;
}

